INSERT INTO scenarios (id, user_id, name, description, global_assumptions, properties, created_at, updated_at, scenario_images, fee_categories, property_photos) OVERRIDING SYSTEM VALUE VALUES (19, 32, 'Development', 'Default development scenario with initial assumptions', '{"id": 9, "userId": null, "icpConfig": {"_research": {"model": "claude-sonnet-4-6", "sections": [{"title": "General Market Overview", "content": "The boutique hotel segment continues to outperform broader lodging categories globally, driven by experiential travel demand, millennial and Gen Z traveler preferences, and the sustained post-pandemic rebound in both leisure and bleisure segments. According to STR and CoStar data, boutique and lifestyle hotels in secondary and tertiary markets have posted ADR growth of 6–9% year-over-year through 2023–2024, outpacing branded chain hotels in many regions. Independent operators and third-party management companies are increasingly positioned as preferred partners for asset owners seeking revenue optimization without franchise fee burdens.\n\nIn the Americas specifically, the convergence of nearshore tourism in Latin America and the resurgence of domestic drive-to leisure markets in the United States presents a compelling dual-market opportunity for a hotel management company with cross-border expertise. Colombia has emerged as one of Latin America''s fastest-growing inbound tourism destinations, while rural New York continues to absorb overflow demand from New York City metropolitan travelers seeking short-stay escapes. Both corridors are underserved by sophisticated, brand-agnostic management platforms capable of delivering institutional-quality operations at the boutique scale.\n\nInvestment fundamentals remain attractive across both geographies, with cap rates for boutique hospitality assets ranging from 7% to 10% depending on location maturity and asset quality. The fragmented ownership landscape — characterized by individual entrepreneurs, family offices, and small REITs — creates significant white space for a professional management company to consolidate operational oversight, implement revenue management systems, and drive NOI improvements of 15–25% within 18–36 months of engagement."}, {"title": "Market Analysis: Medellín & Cartagena", "content": "Medellín has undergone one of the most dramatic urban transformations in Latin American history, evolving from a city associated with insecurity into a globally recognized hub for innovation, design tourism, and medical travel. Boutique hotel inventory in El Poblado, Laureles, and the emerging Envigado corridor is growing rapidly, yet quality management infrastructure lags behind asset development. Average daily rates for upper-boutique properties range from $180–$240 USD, with occupancy levels stabilizing at 62–68% post-pandemic. Demand drivers include the city''s robust digital nomad ecosystem, international conference activity at Plaza Mayor, and year-round temperate climate — factors that contribute to lower seasonality risk compared to coastal destinations.\n\nCartagena operates as Colombia''s premier luxury coastal destination, with the Walled City (Ciudad Amurallada) and Getsemaní neighborhoods commanding premium boutique rates of $250–$380 USD ADR during high season (December–April and July). The UNESCO World Heritage designation provides a durable demand moat, attracting high-net-worth travelers from North America, Europe, and increasingly the Middle East. However, the market faces meaningful seasonality compression — low season occupancy can dip to 48–55% — and infrastructure constraints including water management and energy reliability create above-average operational complexity requiring experienced on-the-ground management.\n\nFor a hotel management company, Colombia presents a first-mover advantage opportunity. The peso''s depreciation against the USD since 2021 has made Colombian assets highly attractive to dollar-denominated investors, accelerating foreign ownership of boutique properties and creating demand for English-fluent, internationally benchmarked management partners. Regulatory frameworks under Colombia''s tourism promotion law (Law 300 and subsequent modifications) offer tax incentives for hotel operators in designated tourism development zones, further improving investment economics.", "locationKey": "Colombia > Antioquia & Bolívar"}, {"title": "Market Analysis: Catskills Region (Highmount, Loch Sheldrake, Eden, Huntsville)", "content": "The Catskills region of upstate New York has experienced a structural demand renaissance since 2020, propelled by remote work migration, NYC metropolitan overflow, and a wave of boutique property conversions from legacy bungalow colonies and defunct Borscht Belt resorts. Towns including Highmount (Ulster County), Loch Sheldrake (Sullivan County), Eden, and Huntsville represent the emerging frontier of this revival — offering lower land acquisition costs and less saturated competitive sets compared to the already-gentrified Woodstock or Hudson corridors. Drive times of 2.5–3.5 hours from Midtown Manhattan position these micro-markets squarely within the weekend escape radius that defines Catskills demand.\n\nBoutique properties in this subregion are achieving ADR of $280–$420 USD on weekends, with blended weekly ADRs of $220–$310 USD, depending on amenity programming and brand positioning. Occupancy rates average 58–72% annually, with pronounced weekend and seasonal peaks (summer and fall foliage). The key value creation lever in these markets is programming — properties that successfully integrate farm-to-table dining, wellness and spa offerings, or arts-and-culture experiences consistently command 30–45% ADR premiums over commodity competitors. Operational sophistication, including dynamic pricing and OTA channel optimization, remains underdeveloped among the largely owner-operated boutique stock.\n\nFrom a management company perspective, the Catskills subregion offers high receptivity among asset owners who acquired or converted properties during the 2020–2022 boom but lack the operational bandwidth to optimize revenue or manage staffing challenges in rural labor markets. Cap rates for stabilized boutique assets in Sullivan and Ulster counties range from 7–9%, with value-add opportunities available in the 9–11% range pre-stabilization. The region''s growing short-term rental regulatory pressure at the county level is also pushing some formerly Airbnb-dependent operators toward professional hotel management structures, creating an additional inbound pipeline.", "locationKey": "United States > New York"}, {"title": "Conclusion & Strategic Recommendations", "content": "The target markets across Colombia and the Catskills share a defining characteristic: they are experiencing demand inflection points that have materially outpaced the development of professional management infrastructure. In both geographies, boutique asset owners face the dual challenge of capitalizing on elevated traveler interest while managing operational complexity — precisely the gap a specialized hotel management company is positioned to fill. The ideal client profile (ICP) in these markets is an asset owner with 10–50 keys, annual revenues of $1M–$8M, limited in-house revenue management capability, and a strong desire to preserve the independent character of their property while accessing institutional-quality operations.\n\nStrategically, the management company should prioritize Cartagena and the Catskills core (Highmount, Loch Sheldrake) as initial entry markets given their more developed inbound tourism infrastructure and higher concentration of target-profile assets. Medellín represents a medium-term growth market where early relationship-building with local developers and family office owners will yield a strong pipeline as the city''s boutique supply continues to expand through 2026–2028. Eden and Huntsville offer longer-horizon opportunities as the Catskills demand wave continues its westward and southward progression through Sullivan County.\n\nKey recommendations include developing a bilingual (English/Spanish) management platform capable of serving both geographies under a unified operating model, investing in a proprietary revenue management and distribution technology stack to demonstrate measurable RevPAR lift within the first 90 days of management engagement, and structuring fee agreements that align incentives through base-plus-incentive models tied to NOI growth. Building a visible thought leadership presence in Colombia''s COTELCO hospitality association and the US-based AAHOA and Small Luxury Hotels networks will accelerate business development across all six target locations."}], "generatedAt": "2026-03-13T15:35:32.656Z", "extractedMetrics": {"avgCapRate": {"unit": "%", "value": 8.2, "description": "Weighted average capitalization rate across stabilized boutique hotel assets in the target markets, with Colombian markets contributing higher cap rate premiums reflecting emerging market risk profiles."}, "nationalAvgAdr": {"unit": "USD", "value": 315, "description": "Blended national average ADR for boutique hotel properties across both the Colombian and US target markets, weighted by market maturity and asset quality benchmarks as of 2024."}, "locationMetrics": [{"avgAdr": {"unit": "USD", "value": 210}, "capRate": {"unit": "%", "value": 9.5}, "location": "Medellín", "avgRevPAR": {"unit": "USD", "value": 137}, "avgOccupancy": {"unit": "%", "value": 65}, "demandGrowthRate": {"unit": "%", "value": 9}, "investmentRating": "A", "avgLandCostPerAcre": {"unit": "USD", "value": 45000}, "competitiveIntensity": "medium"}, {"avgAdr": {"unit": "USD", "value": 310}, "capRate": {"unit": "%", "value": 9}, "location": "Cartagena", "avgRevPAR": {"unit": "USD", "value": 189}, "avgOccupancy": {"unit": "%", "value": 61}, "demandGrowthRate": {"unit": "%", "value": 7}, "investmentRating": "A-", "avgLandCostPerAcre": {"uni